// Original beam / trail gradient ramp (VFX_ASSETS WS-E).
//
// Generates a small grayscale ramp and writes it to
// public/assets/vfx/beam_ramp.webp. Generated by us (ASSETS.md "Original") — no
// third-party download. The VFX manager samples it as the `alphaMap` for beams,
// projectile trails, and lightning ribbons (three reads the green channel). With
// the file absent, vfx.ts falls back to the identical procedural DataTexture, so
// the boot floor is unchanged — this just makes the ramp authorable.
//
// Profile matches beamRampTexture(): a soft core that fades toward both ends and
// never reaches full black, so the additive read stays glowing at the tips.
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import sharp from 'sharp';

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..', '..');
const OUT = path.join(ROOT, 'public/assets/vfx/beam_ramp.webp');
const W = 64;
const H = 4;

const data = Buffer.alloc(W * H * 3);
for (let x = 0; x < W; x++) {
  const u = x / (W - 1);
  const endFade = Math.sin(Math.PI * u); // 0 at both ends, 1 at center
  const core = 0.28 + endFade * 0.72;
  const v = Math.round(255 * Math.max(0, Math.min(1, core)));
  for (let y = 0; y < H; y++) {
    const i = (y * W + x) * 3;
    data[i] = v;
    data[i + 1] = v;
    data[i + 2] = v;
  }
}

fs.mkdirSync(path.dirname(OUT), { recursive: true });
await sharp(data, { raw: { width: W, height: H, channels: 3 } })
  .webp({ lossless: true, effort: 6 })
  .toFile(OUT);

console.log(`wrote ${path.relative(ROOT, OUT)}`);
